package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.FieldNamingStrategy;
import com.google.gson.Gson;
import com.google.gson.JsonIOException;
import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.Excluder;
import com.google.gson.internal.reflect.ReflectionHelper;
import com.google.gson.reflect.TypeToken;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.lang.reflect.Modifier;
import java.util.Collections;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectiveTypeAdapterFactoryGetBoundFieldsTest {

  private ReflectiveTypeAdapterFactory factory;
  private ConstructorConstructor constructorConstructor;
  private FieldNamingStrategy fieldNamingStrategy;
  private Excluder excluder;
  private JsonAdapterAnnotationTypeAdapterFactory jsonAdapterFactory;
  private List<ReflectionAccessFilter> reflectionFilters;

  @BeforeEach
  void setUp() {
    constructorConstructor = mock(ConstructorConstructor.class);
    fieldNamingStrategy = mock(FieldNamingStrategy.class);
    excluder = mock(Excluder.class);
    jsonAdapterFactory = mock(JsonAdapterAnnotationTypeAdapterFactory.class);
    reflectionFilters = Collections.emptyList();
    factory = new ReflectiveTypeAdapterFactory(
        constructorConstructor,
        fieldNamingStrategy,
        excluder,
        jsonAdapterFactory,
        reflectionFilters);
  }

  @Test
  void getBoundFields_interface_returnsEmptyMap() throws Exception {
    Class<?> iface = Runnable.class;
    TypeToken<?> typeToken = TypeToken.get(iface);

    Map<String, Object> result = invokeGetBoundFields(factory, mock(Gson.class), typeToken, iface, false, false);

    assertTrue(result.isEmpty());
  }

  @Test
  void getBoundFields_classWithNoFields_returnsEmptyMap() throws Exception {
    class EmptyClass {}

    Class<?> clazz = EmptyClass.class;
    TypeToken<?> typeToken = TypeToken.get(clazz);

    Map<String, Object> result = invokeGetBoundFields(factory, mock(Gson.class), typeToken, clazz, false, false);

    assertTrue(result.isEmpty());
  }

  @Test
  void getBoundFields_classWithOneField_includesField() throws Exception {
    class TestClass {
      public int publicField = 1;
    }
    Class<?> clazz = TestClass.class;
    TypeToken<?> typeToken = TypeToken.get(clazz);
    Gson context = mock(Gson.class);

    ReflectiveTypeAdapterFactory spyFactory = Mockito.spy(factory);
    doReturn(true).when(spyFactory).includeField(any(Field.class), eq(true));
    doReturn(true).when(spyFactory).includeField(any(Field.class), eq(false));
    doReturn(List.of("publicField")).when(spyFactory).getFieldNames(any(Field.class));
    doReturn(mock(ReflectiveTypeAdapterFactory.BoundField.class))
        .when(spyFactory)
        .createBoundField(any(Gson.class), any(Field.class), any(), anyString(), any(), anyBoolean(), anyBoolean(), anyBoolean());

    Map<String, ReflectiveTypeAdapterFactory.BoundField> result =
        invokeGetBoundFields(spyFactory, context, typeToken, clazz, false, false);

    assertEquals(1, result.size());
    assertTrue(result.containsKey("publicField"));
  }

  @Test
  void getBoundFields_classWithInheritedField_blockAll_throwsJsonIOException() throws Exception {
    class SuperClass {
      public int inheritedField;
    }
    class SubClass extends SuperClass {}

    Class<?> clazz = SubClass.class;
    TypeToken<?> typeToken = TypeToken.get(clazz);
    Gson context = mock(Gson.class);

    ReflectionAccessFilter filter = mock(ReflectionAccessFilter.class);
    List<ReflectionAccessFilter> filters = List.of(filter);

    ReflectiveTypeAdapterFactory factoryWithFilter = new ReflectiveTypeAdapterFactory(
        constructorConstructor,
        fieldNamingStrategy,
        excluder,
        jsonAdapterFactory,
        filters);

    when(filter.filterResult(eq(SuperClass.class))).thenReturn(FilterResult.BLOCK_ALL);

    JsonIOException thrown = assertThrows(JsonIOException.class,
        () -> invokeGetBoundFields(factoryWithFilter, context, typeToken, clazz, false, false));
    assertTrue(thrown.getMessage().contains("ReflectionAccessFilter does not permit using reflection"));
  }

  @Test
  void getBoundFields_classWithInheritedField_blockInaccessible_setsBlockInaccessible() throws Exception {
    class SuperClass {
      public int inheritedField;
    }
    class SubClass extends SuperClass {}

    Class<?> clazz = SubClass.class;
    TypeToken<?> typeToken = TypeToken.get(clazz);
    Gson context = mock(Gson.class);

    ReflectionAccessFilter filter = mock(ReflectionAccessFilter.class);
    List<ReflectionAccessFilter> filters = List.of(filter);

    ReflectiveTypeAdapterFactory factoryWithFilter = Mockito.spy(new ReflectiveTypeAdapterFactory(
        constructorConstructor,
        fieldNamingStrategy,
        excluder,
        jsonAdapterFactory,
        filters));

    when(filter.filterResult(eq(SuperClass.class))).thenReturn(FilterResult.BLOCK_INACCESSIBLE);
    doReturn(true).when(factoryWithFilter).includeField(any(Field.class), anyBoolean());
    doReturn(List.of("inheritedField")).when(factoryWithFilter).getFieldNames(any(Field.class));
    doReturn(mock(ReflectiveTypeAdapterFactory.BoundField.class))
        .when(factoryWithFilter)
        .createBoundField(any(Gson.class), any(Field.class), any(), anyString(), any(), anyBoolean(), anyBoolean(), eq(true));

    Map<String, ReflectiveTypeAdapterFactory.BoundField> result =
        invokeGetBoundFields(factoryWithFilter, context, typeToken, clazz, false, false);

    assertTrue(result.containsKey("inheritedField"));
  }

  @Test
  void getBoundFields_recordWithStaticField_deserializeFalse() throws Exception {
    record RecordWithStatic(int a) {
      static int staticField = 10;
    }

    Class<?> clazz = RecordWithStatic.class;
    TypeToken<?> typeToken = TypeToken.get(clazz);
    Gson context = mock(Gson.class);

    ReflectiveTypeAdapterFactory spyFactory = Mockito.spy(factory);
    doReturn(true).when(spyFactory).includeField(any(Field.class), eq(true));
    doReturn(true).when(spyFactory).includeField(any(Field.class), eq(false));
    doReturn(List.of("a")).when(spyFactory).getFieldNames(any(Field.class));
    doReturn(mock(ReflectiveTypeAdapterFactory.BoundField.class))
        .when(spyFactory)
        .createBoundField(any(Gson.class), any(Field.class), any(), anyString(), any(), anyBoolean(), anyBoolean(), anyBoolean());

    Map<String, ReflectiveTypeAdapterFactory.BoundField> result =
        invokeGetBoundFields(spyFactory, context, typeToken, clazz, false, true);

    assertTrue(result.containsKey("a"));
    assertFalse(result.containsKey("staticField"));
  }

  @Test
  void getBoundFields_fieldWithSerializedNameOnAccessor_throwsJsonIOException() throws Exception {
    class RecordWithSerializedName {
      public int value;
    }

    Class<?> clazz = RecordWithSerializedName.class;
    TypeToken<?> typeToken = TypeToken.get(clazz);
    Gson context = mock(Gson.class);

    ReflectiveTypeAdapterFactory spyFactory = Mockito.spy(factory);
    doReturn(true).when(spyFactory).includeField(any(Field.class), anyBoolean());
    doReturn(List.of("value")).when(spyFactory).getFieldNames(any(Field.class));

    Method accessor = mock(Method.class);
    when(accessor.getAnnotation(SerializedName.class)).thenReturn(mock(SerializedName.class));
    when(spyFactory.getClass().getDeclaredMethod("createBoundField",
        Gson.class, Field.class, Method.class, String.class, TypeToken.class, boolean.class, boolean.class, boolean.class))
        .thenCallRealMethod();

    // We need to mock ReflectionHelper.getAccessor to return accessor with SerializedName annotation
    try (MockedStatic<ReflectionHelper> mockedReflectionHelper = Mockito.mockStatic(ReflectionHelper.class)) {
      mockedReflectionHelper.when(() -> ReflectionHelper.getAccessor(eq(clazz), any(Field.class))).thenReturn(accessor);
      JsonIOException thrown = assertThrows(JsonIOException.class,
          () -> invokeGetBoundFields(spyFactory, context, typeToken, clazz, false, true));
      assertTrue(thrown.getMessage().contains("@SerializedName on"));
    }
  }

  @SuppressWarnings("unchecked")
  private <T> Map<String, T> invokeGetBoundFields(
      ReflectiveTypeAdapterFactory factory,
      Gson context,
      TypeToken<?> type,
      Class<?> raw,
      boolean blockInaccessible,
      boolean isRecord) throws Exception {
    Method method = ReflectiveTypeAdapterFactory.class.getDeclaredMethod(
        "getBoundFields", Gson.class, TypeToken.class, Class.class, boolean.class, boolean.class);
    method.setAccessible(true);
    return (Map<String, T>) method.invoke(factory, context, type, raw, blockInaccessible, isRecord);
  }
}
